#!/usr/bin/env bash
# manage-a-poc-technical-validatio.sh — Manage a POC / technical validation（管理一次技术验证 / POC） SOP walkthrough for B2B 大客户销售.
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="B2B 大客户销售"
WORKFLOW="Manage a POC / technical validation（管理一次技术验证 / POC）"

usage() {
  cat <<EOF
manage-a-poc-technical-validatio.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./manage-a-poc-technical-validatio.sh             # interactive
  ./manage-a-poc-technical-validatio.sh --dry-run
  ./manage-a-poc-technical-validatio.sh --json
  ./manage-a-poc-technical-validatio.sh --explain
  ./manage-a-poc-technical-validatio.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "Manage a POC / technical validation（管理一次技术验证 / POC）" 工作流。

一句话: When a buyer wants proof before buying, run a *time-boxed* technical validation with **pre-agreed success criteria** — done right it's a "yes" accelerant; done wrong it becomes endless free consulting. The AE↔SE collaboration motion. (evidence: [T03-S014, T03-S015])

入门 SOP 共 5 步, 失败模式自检 4 项。

相关心智模型:
  • 问 ⇄ 教 ⇄ 筛:三派第一性张力,资深人按层混用: 复杂销售的方法论分三派——诊断式提问(SPIN/Gap:「客户有答案,问到痛点不可否认为止」)⇄ 挑战式教学(Challenger:「客户对自己问题的认知是错的,用商业洞见 reframe」)⇄ 资格
  • 头号对手是「不决策」,不是竞品: 预测内丢单的最大去向不是输给对手,而是客户「什么都不做」——维持现状;且一旦购买意向形成,买方更怕「搞砸」(FOMU)而非「错过」(FOMO),所以晚期停滞要按「犹豫」处理(去风险),不是按「异议」处

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "**Qualify whether a POC is even warranted** — confirm pain, EB engagement, and that a POC (not a demo/reference) is the right proof. (evidence: [T03-S014])"
  "**Define success criteria + exit criteria up front** — write down, with the buyer, exactly what \"success\" means (which use cases, what threshold, by when), and what happens if it's met. (evidence: [T03-S008, T03-S015])"
  "**Set mutual ownership + timeline** — name who does what on both sides, with dates (often inside the Mutual Action Plan). (evidence: [T03-S017])"
  "**Run the POC with the SE bridging tech↔value** — the Sales Engineer (trusted technical advisor) connects technical capabilities to the quantified business value at each step. (evidence: [T03-S014])"
  "**Review the POV with the client + document the win** — formally review results against the criteria with the buyer; capture metrics for the business case. (evidence: [T03-S015])"
)
declare -a FAILURE_MODES=(
  "**No success criteria set up front → POC becomes endless free consulting**: with no finish line, the buyer keeps scope-creeping and the deal drags 6-8+ weeks. Avoid: write buyer-agreed success + exit criteria *before* day 1; if the buyer won't agree to criteria, that's a disqualify signal. (evidence: [T03-S015])"
  "**A one-sided POC the SE does alone**: no buyer effort = weak intent + a result the buyer didn't co-own. Avoid: mutual ownership with dates inside a MAP. (evidence: [T03-S017])"
  "**Feature-passes-but-no-value POC**: tech works, but it's untied to a business outcome → lose to a cheaper competitor. Avoid: SE connects each capability to the quantified business value. (evidence: [T03-S014])"
  "**Running a POC for an unqualified / no-EB deal**: weeks of scarce SE time on a deal that was never real. Avoid: qualify the POC (pain + EB + right-proof) before committing the SE. (evidence: [T03-S014])"
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "manage-a-poc-technical-validatio-walkthrough"
fi
